import { readFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';

declare const __MCP_VERSION__: string | undefined;

function getVersion(): string {
  if (typeof __MCP_VERSION__ !== 'undefined') {
    return __MCP_VERSION__;
  }
  // Fallback for dev mode (tsx)
  const __dirname = dirname(fileURLToPath(import.meta.url));
  const pkg = JSON.parse(
    readFileSync(join(__dirname, '../../package.json'), 'utf-8')
  ) as { version: string };
  return pkg.version;
}

export const MCP_VERSION = getVersion();

export const DIST_TAG = MCP_VERSION.includes('-beta') ? 'beta' : 'latest';

export function getInstallPackageSpecifier(version: string): string {
  // Prerelease builds (beta, canary, PR builds, etc.) should reinstall the
  // exact build the user is running instead of silently switching channels.
  return version.includes('-') ? version : 'latest';
}

export const INSTALL_PACKAGE_SPECIFIER =
  getInstallPackageSpecifier(MCP_VERSION);
